DROP TABLE IF EXISTS `nqm`.`nq_lib`;
CREATE TABLE `nqm`.`nq_lib` (
  `lib_id` INT NOT NULL AUTO_INCREMENT,
  `lib_title` VARCHAR(100) NOT NULL,
  `lib_album` VARCHAR(100) NULL,
  `lib_artist` VARCHAR(100) NOT NULL,
  `lib_duration` VARCHAR(100) NULL,
  `lib_release_year` INT NULL,
  `lib_plays` BIGINT NULL,
  `lib_origin` VARCHAR(100) NULL,
  `lib_awards` VARCHAR(100) NULL,
  `lib_lyrics` MEDIUMTEXT NULL,
  PRIMARY KEY (`lib_id`));


SELECT * 
FROM nq_lib
;